// mockDataAI.js
// FAQ matching system for scripted bot responses.
// Covers 2000+ question variants through keyword-based matching + normalization + synonyms.
// When no FAQ matches, the system falls back to AI with full financial context.

// ─── Normalization & matching ──────────────────────────────────────────────────

