  копить: 'накопить', сберегать: 'накопить', откладывать: 'накопить',
  сохранить: 'накопить', сберечь: 'накопить',
  дешевле: 'экономить', сэкономить: 'экономить', экономия: 'экономить',
  оптимизировать: 'экономить', сократить: 'экономить', уменьшить: 'экономить',
